// client/src/components/Admin/Dashboard.jsx
import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { userService } from '../../services/userService';
import { busService } from '../../services/busService';
import { 
  ChartBarIcon, 
  UserGroupIcon, 
  UserIcon, 
  AcademicCapIcon,
  TruckIcon,
  ClockIcon,
  MapPinIcon,
  ArrowTrendingUpIcon,
  ArrowTrendingDownIcon
} from '@heroicons/react/20/solid';
import StatCard from '../UI/StatCard';
import ChartComponent from '../UI/ChartComponent';

const AdminDashboard = () => {
  const [stats, setStats] = useState({
    totalUsers: 0,
    totalStudents: 0,
    totalDrivers: 0,
    totalAdmins: 0,
    totalBuses: 0,
    activeBuses: 0,
    delayedBuses: 0
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      setLoading(true);
      
      // Mock data for demonstration
      setStats({
        totalUsers: 1254,
        totalStudents: 1023,
        totalDrivers: 45,
        totalAdmins: 8,
        totalBuses: 38,
        activeBuses: 32,
        delayedBuses: 6
      });

    } catch (error) {
      console.error('Error fetching dashboard data:', error);
    } finally {
      setLoading(false);
    }
  };

  // Chart data
  const chartData = {
    labels: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'],
    datasets: [
      {
        label: 'Active Users',
        data: [650, 590, 800, 810, 560, 550, 400],
        borderColor: 'rgb(59, 130, 246)',
        backgroundColor: 'rgba(59, 130, 246, 0.1)',
        tension: 0.4,
        fill: true
      },
      {
        label: 'Bus Trips',
        data: [280, 480, 400, 190, 860, 270, 900],
        borderColor: 'rgb(16, 185, 129)',
        backgroundColor: 'rgba(16, 185, 129, 0.1)',
        tension: 0.4,
        fill: true
      }
    ]
  };

  const chartOptions = {
    responsive: true,
    plugins: {
      legend: {
        position: 'top',
      },
    },
    scales: {
      y: {
        beginAtZero: true,
        grid: {
          drawBorder: false,
        }
      },
      x: {
        grid: {
          display: false,
        }
      }
    }
  };

  const quickActions = [
    { title: 'Add New User', icon: UserGroupIcon, color: 'bg-blue-500', link: '/admin/users' },
    { title: 'Manage Buses', icon: TruckIcon, color: 'bg-green-500', link: '/admin/buses' },
    { title: 'Live Monitor', icon: MapPinIcon, color: 'bg-purple-500', link: '/admin/monitor' },
    { title: 'Reports', icon: ChartBarIcon, color: 'bg-amber-500', link: '#' },
  ];

  return (
    <div className="w-full space-y-8">
      {/* Header Section */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-8">
        <div className="flex flex-col md:flex-row md:items-center md:justify-between">
          <div className="flex-1">
            <h1 className="text-4xl font-bold text-gray-900 tracking-tight">Admin Dashboard</h1>
            <p className="mt-2 text-base text-gray-600">Welcome back! Here's your system overview for today.</p>
          </div>
          <div className="flex items-center gap-4 mt-6 md:mt-0">
            <span className="inline-flex items-center gap-2 px-4 py-2 rounded-full text-sm font-semibold bg-green-50 text-green-700 border border-green-200">
              <span className="inline-block w-2.5 h-2.5 rounded-full bg-green-500"></span>
              System Active
            </span>
            <button className="px-6 py-2 bg-blue-600 text-white text-sm font-semibold rounded-lg hover:bg-blue-700 transition-colors duration-200 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2">
              Refresh
            </button>
          </div>
        </div>
      </div>

      {/* Main Stats Grid - 4 Columns on Desktop */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard
          title="Total Users"
          value={stats.totalUsers}
          icon={UserGroupIcon}
          color="blue"
          trend="+12%"
          trendUp={true}
          loading={loading}
        />
        <StatCard
          title="Students"
          value={stats.totalStudents}
          icon={AcademicCapIcon}
          color="green"
          trend="+8%"
          trendUp={true}
          loading={loading}
        />
        <StatCard
          title="Drivers"
          value={stats.totalDrivers}
          icon={UserIcon}
          color="purple"
          trend="+5%"
          trendUp={true}
          loading={loading}
        />
        <StatCard
          title="Total Buses"
          value={stats.totalBuses}
          icon={TruckIcon}
          color="amber"
          trend="+15%"
          trendUp={true}
          loading={loading}
        />
      </div>

      {/* Secondary Stats Grid - 3 Columns on Desktop */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {/* Active Buses Card */}
        <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6 hover:shadow-md transition-shadow duration-200">
          <div className="flex items-start justify-between">
            <div>
              <p className="text-xs font-semibold text-gray-600 uppercase tracking-widest">Active Buses</p>
              <p className="text-4xl font-bold text-gray-900 mt-4">{stats.activeBuses}</p>
              <div className="flex items-center gap-2 mt-4">
                <ArrowTrendingUpIcon className="w-4 h-4 text-green-600" />
                <span className="text-sm font-semibold text-green-700">All systems operational</span>
              </div>
            </div>
            <div className="p-3 rounded-lg bg-green-100 flex-shrink-0">
              <TruckIcon className="w-6 h-6 text-green-600" />
            </div>
          </div>
        </div>

        {/* Delayed Buses Card */}
        <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6 hover:shadow-md transition-shadow duration-200">
          <div className="flex items-start justify-between">
            <div>
              <p className="text-xs font-semibold text-gray-600 uppercase tracking-widest">Delayed Buses</p>
              <p className="text-4xl font-bold text-gray-900 mt-4">{stats.delayedBuses}</p>
              <div className="flex items-center gap-2 mt-4">
                <ArrowTrendingDownIcon className="w-4 h-4 text-amber-600" />
                <span className="text-sm font-semibold text-amber-700">Needs attention</span>
              </div>
            </div>
            <div className="p-3 rounded-lg bg-amber-100 flex-shrink-0">
              <ClockIcon className="w-6 h-6 text-amber-600" />
            </div>
          </div>
        </div>

        {/* System Admins Card */}
        <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6 hover:shadow-md transition-shadow duration-200">
          <div className="flex items-start justify-between">
            <div>
              <p className="text-xs font-semibold text-gray-600 uppercase tracking-widest">System Admins</p>
              <p className="text-4xl font-bold text-gray-900 mt-4">{stats.totalAdmins}</p>
              <p className="text-sm font-medium text-gray-600 mt-4">Managing system operations</p>
            </div>
            <div className="p-3 rounded-lg bg-blue-100 flex-shrink-0">
              <UserGroupIcon className="w-6 h-6 text-blue-600" />
            </div>
          </div>
        </div>
      </div>

      {/* Chart and Actions Section */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Chart */}
        <div className="lg:col-span-2">
          <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
            <div className="flex items-center justify-between mb-8">
              <h2 className="text-lg font-bold text-gray-900">Weekly Activity Overview</h2>
              <select className="text-sm border border-gray-300 rounded-lg px-4 py-2 bg-white hover:border-gray-400 focus:border-blue-500 focus:ring-1 focus:ring-blue-500 transition-colors">
                <option>Last 7 days</option>
                <option>Last 30 days</option>
                <option>Last quarter</option>
              </select>
            </div>
            <div className="h-80">
              <ChartComponent data={chartData} options={chartOptions} type="line" />
            </div>
          </div>
        </div>

        {/* Sidebar with Quick Actions and Recent Activity */}
        <div>
          <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
            <h2 className="text-lg font-bold text-gray-900 mb-6">Quick Actions</h2>
            
            {/* Quick Actions List */}
            <div className="space-y-3 mb-8">
              {quickActions.map((action, index) => (
                <Link
                  key={index}
                  to={action.link}
                  className="flex items-center gap-3 px-4 py-3 rounded-lg border border-gray-200 hover:border-blue-300 hover:bg-blue-50 transition-all group"
                >
                  <div className={`${action.color} p-2 rounded-lg text-white flex-shrink-0`}>
                    <action.icon className="w-4 h-4" />
                  </div>
                  <span className="text-sm font-semibold text-gray-700 group-hover:text-blue-700 flex-1">
                    {action.title}
                  </span>
                </Link>
              ))}
            </div>

            {/* Recent Activity */}
            <div className="pt-8 border-t border-gray-200">
              <h3 className="text-sm font-bold text-gray-900 mb-4">Recent Activity</h3>
              <div className="space-y-4">
                {[
                  { text: 'New student registration', time: '2 min ago' },
                  { text: 'Bus #12 location updated', time: '5 min ago' },
                  { text: 'Driver assigned to Bus #08', time: '10 min ago' },
                ].map((activity, index) => (
                  <div key={index} className="flex gap-3">
                    <div className="flex-shrink-0 pt-1">
                      <span className="inline-block w-2 h-2 rounded-full bg-blue-500"></span>
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="text-sm font-medium text-gray-700">{activity.text}</p>
                      <p className="text-xs text-gray-500 mt-0.5">{activity.time}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;