// client/src/components/Admin/BulkUserForm.jsx
import Modal from '../UI/Modal';
import { userService } from '../../services/userService';

const BulkUserForm = ({ onSuccess, onCancel }) => {
  const [importMethod, setImportMethod] = useState('excel'); // 'excel', 'csv', 'json', 'clipboard'
  const [csvText, setCsvText] = useState('');
  const [jsonText, setJsonText] = useState('');
  const [clipboardText, setClipboardText] = useState('');
  const [loading, setLoading] = useState(false);
  const [errors, setErrors] = useState([]);
  const [previewData, setPreviewData] = useState([]);

  // Excel table rows
  const [rows, setRows] = useState([
    { name: '', email: '', role: 'student', phone: '', address: '' }
  ]);

  const addRow = () => {
    setRows([...rows, { name: '', email: '', role: 'student', phone: '', address: '' }]);
  };

  const removeRow = (index) => {
    if (rows.length > 1) {
      const newRows = [...rows];
      newRows.splice(index, 1);
      setRows(newRows);
    }
  };

  const updateRow = (index, field, value) => {
    const newRows = [...rows];
    newRows[index][field] = value;
    setRows(newRows);
  };

  const validateRow = (row) => {
    const errors = [];
    if (!row.name.trim()) errors.push('Name is required');
    if (!row.email.includes('@')) errors.push('Valid email is required');
    return errors.length === 0;
  };

  const parseData = (method) => {
    try {
      let parsedData = [];
      
      switch(method) {
        case 'csv':
          parsedData = userService.parseCSV(csvText);
          break;
        case 'json':
          parsedData = userService.parseJSON(jsonText);
          break;
        case 'clipboard':
          parsedData = userService.parseClipboard(clipboardText);
          break;
        case 'excel':
          parsedData = rows.map((row, index) => ({
            id: index + 1,
            name: row.name,
            email: row.email,
            role: row.role,
            phone: row.phone,
            address: row.address,
            status: 'pending'
          })).filter(row => row.name || row.email);
          break;
      }
      
      setPreviewData(parsedData);
      setErrors([]);
      return parsedData;
    } catch (error) {
      setErrors([error.message]);
      return [];
    }
  };

  const handleSubmit = async () => {
    setLoading(true);
    setErrors([]);

    const data = parseData(importMethod);
    
    if (data.length === 0) {
      setErrors(['No valid data to import']);
      setLoading(false);
      return;
    }

    // Validate all rows
    const validationErrors = [];
    data.forEach((user, index) => {
      if (!validateRow(user)) {
        validationErrors.push(`Row ${index + 1}: Invalid data`);
      }
    });

    if (validationErrors.length > 0) {
      setErrors(validationErrors);
      setLoading(false);
      return;
    }

    try {
      const response = await userService.bulkImportUsers(data);
      
      if (response.success) {
        alert(`Successfully imported ${response.count || data.length} users`);
        onSuccess();
      } else {
        setErrors([response.message || 'Import failed']);
      }
    } catch (error) {
      setErrors(['Failed to import users. Please try again.']);
      console.error('Bulk import error:', error);
    } finally {
      setLoading(false);
    }
  };

  const downloadTemplate = () => {
    const template = `name,email,role,phone,address
John Doe,john@example.com,student,+1234567890,123 Main St
Jane Smith,jane@example.com,admin,+1234567891,456 Oak Ave`;

    const blob = new Blob([template], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'user_import_template.csv';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const pasteFromClipboard = async () => {
    try {
      const text = await navigator.clipboard.readText();
      setClipboardText(text);
      parseData('clipboard');
    } catch (error) {
      setErrors(['Failed to read from clipboard']);
    }
  };

  return (
    <div className="p-4 max-h-[80vh] overflow-y-auto">
      {/* Import Method Tabs */}
      <div className="border-b border-gray-200 mb-6">
        <div className="flex flex-wrap gap-2">
          {['excel', 'csv', 'json', 'clipboard'].map((method) => (
            <button
              key={method}
              className={`px-4 py-2 font-medium text-sm rounded-t-lg capitalize ${
                importMethod === method 
                  ? 'bg-blue-50 text-blue-600 border-b-2 border-blue-500' 
                  : 'text-gray-500 hover:text-gray-700'
              }`}
              onClick={() => setImportMethod(method)}
            >
              <i className={`fas fa-${method === 'excel' ? 'table' : method === 'csv' ? 'file-csv' : method === 'json' ? 'file-code' : 'paste'} mr-2`}></i>
              {method}
            </button>
          ))}
        </div>
      </div>

      {/* Template Download */}
      <div className="mb-6 p-4 bg-blue-50 rounded-lg border border-blue-200">
        <div className="flex items-center justify-between">
          <div>
            <h4 className="font-medium text-blue-900">Need a template?</h4>
            <p className="text-sm text-blue-700">Download our CSV template to get started</p>
          </div>
          <button
            onClick={downloadTemplate}
            className="px-4 py-2 bg-white text-blue-600 border border-blue-300 rounded-lg hover:bg-blue-50 transition-colors flex items-center gap-2"
          >
            <i className="fas fa-download"></i>
            Download Template
          </button>
        </div>
      </div>

      {/* Import Method Content */}
      {importMethod === 'excel' && (
        <div className="mb-6">
          <div className="flex justify-between items-center mb-4">
            <h3 className="text-lg font-semibold text-gray-900">Excel-like Table</h3>
            <button
              onClick={addRow}
              className="px-4 py-2 bg-green-500 text-white rounded-lg hover:bg-green-600 transition-colors flex items-center gap-2"
            >
              <i className="fas fa-plus"></i>
              Add Row
            </button>
          </div>

          <div className="overflow-x-auto border border-gray-200 rounded-lg">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">#</th>
                  <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Name *</th>
                  <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Email *</th>
                  <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Role</th>
                  <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Phone</th>
                  <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Address</th>
                  <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Actions</th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {rows.map((row, index) => (
                  <tr key={index} className="hover:bg-gray-50">
                    <td className="px-4 py-3 text-sm text-gray-500">{index + 1}</td>
                    <td className="px-4 py-3">
                      <input
                        type="text"
                        value={row.name}
                        onChange={(e) => updateRow(index, 'name', e.target.value)}
                        className="w-full px-3 py-2 border border-gray-300 rounded focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                        placeholder="John Doe"
                      />
                    </td>
                    <td className="px-4 py-3">
                      <input
                        type="email"
                        value={row.email}
                        onChange={(e) => updateRow(index, 'email', e.target.value)}
                        className="w-full px-3 py-2 border border-gray-300 rounded focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                        placeholder="john@example.com"
                      />
                    </td>
                    <td className="px-4 py-3">
                      <select
                        value={row.role}
                        onChange={(e) => updateRow(index, 'role', e.target.value)}
                        className="w-full px-3 py-2 border border-gray-300 rounded focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                      >
                        <option value="student">Student</option>
                        <option value="driver">Driver</option>
                        <option value="admin">Admin</option>
                      </select>
                    </td>
                    <td className="px-4 py-3">
                      <input
                        type="tel"
                        value={row.phone}
                        onChange={(e) => updateRow(index, 'phone', e.target.value)}
                        className="w-full px-3 py-2 border border-gray-300 rounded focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                        placeholder="+1234567890"
                      />
                    </td>
                    <td className="px-4 py-3">
                      <input
                        type="text"
                        value={row.address}
                        onChange={(e) => updateRow(index, 'address', e.target.value)}
                        className="w-full px-3 py-2 border border-gray-300 rounded focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                        placeholder="123 Main St"
                      />
                    </td>
                    <td className="px-4 py-3">
                      <button
                        onClick={() => removeRow(index)}
                        className="px-3 py-1 bg-red-100 text-red-700 rounded hover:bg-red-200 transition-colors"
                        disabled={rows.length === 1}
                      >
                        <i className="fas fa-trash"></i>
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {importMethod === 'csv' && (
        <div className="mb-6">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">CSV Import</h3>
          <textarea
            value={csvText}
            onChange={(e) => setCsvText(e.target.value)}
            className="w-full h-48 px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 font-mono text-sm"
            placeholder="name,email,role,phone,address
John Doe,john@example.com,student,+1234567890,123 Main St"
          />
          <button
            onClick={() => parseData('csv')}
            className="mt-2 px-4 py-2 bg-blue-100 text-blue-700 rounded-lg hover:bg-blue-200"
          >
            Preview Data
          </button>
        </div>
      )}

      {importMethod === 'json' && (
        <div className="mb-6">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">JSON Import</h3>
          <textarea
            value={jsonText}
            onChange={(e) => setJsonText(e.target.value)}
            className="w-full h-48 px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 font-mono text-sm"
            placeholder='[
  {
    "name": "John Doe",
    "email": "john@example.com",
    "role": "student",
    "phone": "+1234567890",
    "address": "123 Main St"
  }
]'
          />
          <button
            onClick={() => parseData('json')}
            className="mt-2 px-4 py-2 bg-blue-100 text-blue-700 rounded-lg hover:bg-blue-200"
          >
            Preview Data
          </button>
        </div>
      )}

      {importMethod === 'clipboard' && (
        <div className="mb-6">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">Paste from Clipboard</h3>
          <div className="flex gap-2 mb-4">
            <button
              onClick={pasteFromClipboard}
              className="px-4 py-2 bg-green-500 text-white rounded-lg hover:bg-green-600 transition-colors flex items-center gap-2"
            >
              <i className="fas fa-paste"></i>
              Paste from Clipboard
            </button>
            <button
              onClick={() => setClipboardText('')}
              className="px-4 py-2 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300"
            >
              Clear
            </button>
          </div>
          <textarea
            value={clipboardText}
            onChange={(e) => setClipboardText(e.target.value)}
            className="w-full h-48 px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 font-mono text-sm"
            placeholder="Paste your data here (CSV, JSON, or tab-separated values)..."
          />
        </div>
      )}

      {/* Preview */}
      {previewData.length > 0 && (
        <div className="mb-6">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">
            Preview ({previewData.length} users)
          </h3>
          <div className="overflow-x-auto border border-gray-200 rounded-lg">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">#</th>
                  <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Name</th>
                  <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Email</th>
                  <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Role</th>
                  <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Status</th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {previewData.slice(0, 5).map((user, index) => (
                  <tr key={index}>
                    <td className="px-4 py-3 text-sm text-gray-500">{index + 1}</td>
                    <td className="px-4 py-3 text-sm text-gray-900">{user.name}</td>
                    <td className="px-4 py-3 text-sm text-gray-900">{user.email}</td>
                    <td className="px-4 py-3 text-sm text-gray-900">{user.role}</td>
                    <td className="px-4 py-3">
                      <span className="px-2 py-1 text-xs bg-yellow-100 text-yellow-800 rounded-full">
                        Pending Import
                      </span>
                    </td>
                  </tr>
                ))}
                {previewData.length > 5 && (
                  <tr>
                    <td colSpan="5" className="px-4 py-3 text-sm text-gray-500 text-center">
                      ... and {previewData.length - 5} more users
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Error Display */}
      {errors.length > 0 && (
        <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-lg">
          <h4 className="font-medium text-red-900 mb-2">Errors:</h4>
          <ul className="text-sm text-red-700 list-disc pl-5">
            {errors.map((error, index) => (
              <li key={index}>{error}</li>
            ))}
          </ul>
        </div>
      )}

      {/* Actions */}
      <div className="flex justify-between items-center pt-6 border-t border-gray-200">
        <button
          onClick={onCancel}
          className="px-6 py-3 border border-gray-300 text-gray-700 rounded-lg font-medium hover:bg-gray-50 transition-colors"
        >
          Cancel
        </button>
        <div className="flex gap-4">
          <div className="text-sm text-gray-600 self-center">
            {previewData.length > 0 ? `${previewData.length} users ready to import` : 'No data to import'}
          </div>
          <button
            onClick={handleSubmit}
            disabled={loading || previewData.length === 0}
            className="px-8 py-3 bg-gradient-to-r from-green-500 to-emerald-600 text-white rounded-lg font-semibold hover:from-green-600 hover:to-emerald-700 transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
          >
            {loading ? (
              <>
                <i className="fas fa-spinner fa-spin"></i>
                Importing...
              </>
            ) : (
              <>
                <i className="fas fa-users"></i>
                Import {previewData.length} Users
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};

export default BulkUserForm;