// client/src/pages/StudentPage.jsx
import React, { useState, useEffect } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { useSocket } from '../contexts/SocketContext';
import Navbar from '../components/Layout/Navbar';
import MapComponent from '../components/Common/MapComponent';
import BusMarker from '../components/Common/BusMarker';
import useGeolocation from '../hooks/useGeolocation';
import { busService } from '../services/busService';

const StudentDashboard = () => {
  const { user } = useAuth();
  const { socket, joinBusRoom } = useSocket();
  const { location, error: locationError, getCurrentPosition } = useGeolocation();
  
  const [bus, setBus] = useState(null);
  const [loading, setLoading] = useState(true);
  const [eta, setEta] = useState(null);
  const [distance, setDistance] = useState(null);
  const [showRoute, setShowRoute] = useState(false);
  const [routeCoordinates, setRouteCoordinates] = useState([]);
  const [lastUpdate, setLastUpdate] = useState(null);

  // Fetch student's bus
  useEffect(() => {
    const fetchBus = async () => {
      try {
        setLoading(true);
        const busData = await busService.getMyBus();
        
        if (busData) {
          setBus(busData);
          
          // Join bus room for real-time updates
          if (busData._id) {
            joinBusRoom(busData._id);
          }
        }
      } catch (error) {
        console.error('Error fetching bus data:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchBus();
  }, [joinBusRoom]);

  // Get student location on mount
  useEffect(() => {
    getCurrentPosition().catch(console.error);
  }, []);

  // Socket listeners for real-time updates
  useEffect(() => {
    if (!socket || !bus?._id) return;

    const handleBusUpdate = (data) => {
      setBus(prev => ({
        ...prev,
        latitude: data.latitude,
        longitude: data.longitude,
        status: data.status,
        updatedAt: data.timestamp
      }));
      setLastUpdate(new Date());
      
      // Recalculate ETA if student location is available
      if (location && data.latitude && data.longitude) {
        calculateETA(data.latitude, data.longitude);
      }
    };

    socket.on('bus-location-update', handleBusUpdate);
    socket.on('bus-live-update', handleBusUpdate);

    return () => {
      socket.off('bus-location-update', handleBusUpdate);
      socket.off('bus-live-update', handleBusUpdate);
    };
  }, [socket, bus?._id, location]);

  // Calculate ETA when locations change
  useEffect(() => {
    if (bus?.latitude && bus?.longitude && location) {
      calculateETA(bus.latitude, bus.longitude);
    }
  }, [bus, location]);

  // Calculate ETA and distance
  const calculateETA = async (busLat, busLng) => {
    if (!location) return;

    try {
      const routeInfo = await busService.getRouteInfo(
        location.latitude,
        location.longitude,
        busLat,
        busLng
      );

      if (routeInfo) {
        if (routeInfo.coordinates) {
          setRouteCoordinates(routeInfo.coordinates);
        }
        
        if (routeInfo.duration) {
          const minutes = Math.round(routeInfo.duration);
          setEta(minutes > 0 ? `${minutes} mins` : 'Arriving now');
        }
        
        if (routeInfo.distance) {
          setDistance(`${routeInfo.distance.toFixed(1)} km`);
        }
      }
    } catch (error) {
      // Fallback calculation using straight-line distance
      const straightLineDistance = calculateStraightDistance(
        location.latitude,
        location.longitude,
        busLat,
        busLng
      );
      
      const estimatedTime = Math.round((straightLineDistance / 30) * 60); // 30 km/h average
      setEta(estimatedTime > 0 ? `${estimatedTime} mins` : 'Arriving now');
      setDistance(`${straightLineDistance.toFixed(1)} km`);
    }
  };

  // Calculate straight-line distance (Haversine formula)
  const calculateStraightDistance = (lat1, lon1, lat2, lon2) => {
    const R = 6371; // Earth's radius in km
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLon = (lon2 - lon1) * Math.PI / 180;
    const a = 
      Math.sin(dLat/2) * Math.sin(dLat/2) +
      Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
      Math.sin(dLon/2) * Math.sin(dLon/2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
    return R * c;
  };

  // Map markers
  const mapMarkers = [
    ...(bus?.latitude && bus?.longitude ? [{
      position: { lat: bus.latitude, lng: bus.longitude },
      iconHtml: `
        <div style="
          width: 50px;
          height: 50px;
          background: #2563eb;
          border-radius: 50%;
          border: 3px solid white;
          box-shadow: 0 4px 15px rgba(37, 99, 235, 0.4);
          display: flex;
          align-items: center;
          justify-content: center;
          color: white;
          font-size: 1.2rem;
        ">
          <i class="fas fa-bus"></i>
        </div>
      `,
      iconSize: [50, 50],
      iconAnchor: [25, 50],
      popup: `
        <div style="padding: 10px; min-width: 200px;">
          <strong>Bus ${bus.busNumber}</strong><br>
          Route: ${bus.routeName || 'N/A'}<br>
          Status: ${bus.status || 'Active'}<br>
          Driver: ${bus.driverName || 'N/A'}
        </div>
      `
    }] : []),
    ...(location ? [{
      position: { lat: location.latitude, lng: location.longitude },
      color: '#10b981',
      size: 35,
      icon: '👨‍🎓',
      popup: `
        <div style="padding: 10px;">
          <strong>Your Location</strong><br>
          ${location.latitude.toFixed(6)}, ${location.longitude.toFixed(6)}
        </div>
      `
    }] : [])
  ];

  // Route data for map
  const mapRoutes = showRoute && routeCoordinates.length > 0 ? [{
    coordinates: routeCoordinates,
    color: '#6366f1',
    weight: 4,
    opacity: 0.7
  }] : bus?.latitude && bus?.longitude && location ? [{
    coordinates: [
      { lat: location.latitude, lng: location.longitude },
      { lat: bus.latitude, lng: bus.longitude }
    ],
    color: '#94a3b8',
    weight: 3,
    opacity: 0.5,
    dashed: true
  }] : [];

  // Center map between bus and student
  const mapCenter = bus?.latitude && bus?.longitude && location 
    ? [
        (bus.latitude + location.latitude) / 2,
        (bus.longitude + location.longitude) / 2
      ]
    : bus?.latitude && bus?.longitude
    ? [bus.latitude, bus.longitude]
    : location
    ? [location.latitude, location.longitude]
    : [20.5937, 78.9629];

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto"></div>
          <p className="mt-4 text-gray-600">Loading your bus information...</p>
        </div>
      </div>
    );
  }

  if (!bus) {
    return (
      <div className="min-h-screen bg-gray-50">
        <Navbar />
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
          <div className="bg-white rounded-xl shadow-lg border border-gray-200 p-8 text-center">
            <div className="w-20 h-20 mx-auto mb-6 rounded-full bg-gray-100 flex items-center justify-center">
              <i className="fas fa-bus-slash text-3xl text-gray-400"></i>
            </div>
            <h2 className="text-2xl font-bold text-gray-900 mb-4">No Bus Assigned</h2>
            <p className="text-gray-600 mb-6">
              You don't have a bus assigned to you yet. Please contact the AIDS Department for assistance.
            </p>
            <button
              onClick={() => window.location.reload()}
              className="px-6 py-3 bg-gradient-to-r from-blue-500 to-blue-600 text-white rounded-lg font-medium hover:from-blue-600 hover:to-blue-700 transition-all"
            >
              <i className="fas fa-sync-alt mr-2"></i>
              Refresh Page
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <Navbar />
      
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Header with Student Info */}
        <div className="mb-8">
          <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4">
            <div>
              <h1 className="text-2xl font-bold text-gray-900">Student Dashboard</h1>
              <div className="mt-2 flex items-center gap-4">
                <div className="flex items-center gap-2">
                  <div className="w-8 h-8 rounded-full bg-gradient-to-r from-blue-500 to-blue-600 flex items-center justify-center text-white">
                    {user?.name?.charAt(0).toUpperCase() || 'S'}
                  </div>
                  <div>
                    <p className="font-medium text-gray-900">{user?.name}</p>
                    <p className="text-sm text-gray-600">Student ID: {user?.studentId}</p>
                  </div>
                </div>
                <div className="hidden md:block px-3 py-1 bg-blue-100 text-blue-800 rounded-full text-sm font-medium">
                  {bus ? `Assigned to Bus ${bus.busNumber}` : 'No Bus Assigned'}
                </div>
              </div>
            </div>
            
            <div className="flex items-center gap-3">
              {bus?.status && (
                <span className={`px-3 py-1 rounded-full text-sm font-medium ${
                  bus.status === 'moving' ? 'bg-green-100 text-green-800' :
                  bus.status === 'stopped' ? 'bg-yellow-100 text-yellow-800' :
                  'bg-gray-100 text-gray-800'
                }`}>
                  {bus.status.toUpperCase()}
                </span>
              )}
              <button
                onClick={() => getCurrentPosition()}
                className="px-4 py-2 bg-white border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors flex items-center gap-2"
              >
                <i className="fas fa-location-crosshairs"></i>
                Refresh Location
              </button>
            </div>
          </div>
        </div>

        {/* Main Content Grid */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* ETA and Bus Info */}
          <div className="lg:col-span-1 space-y-6">
            {/* ETA Card */}
            <div className="bg-gradient-to-br from-blue-500 to-blue-600 rounded-xl shadow-lg text-white p-6">
              <div className="flex items-center gap-3 mb-4">
                <div className="w-12 h-12 rounded-lg bg-white/20 flex items-center justify-center backdrop-blur-sm">
                  <i className="fas fa-clock text-xl"></i>
                </div>
                <div>
                  <h3 className="text-lg font-semibold">Estimated Arrival</h3>
                  <p className="text-blue-100 text-sm">Live tracking enabled</p>
                </div>
              </div>
              
              <div className="text-center py-4">
                <div className="text-5xl font-bold mb-2">{eta || '--:--'}</div>
                <p className="text-blue-100">{distance || 'Calculating distance...'}</p>
              </div>
              
              <div className="mt-4 pt-4 border-t border-blue-400/30">
                <div className="flex justify-between text-sm">
                  <span>Last Updated</span>
                  <span>{lastUpdate ? lastUpdate.toLocaleTimeString() : 'Never'}</span>
                </div>
              </div>
            </div>

            {/* Bus Details Card */}
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
              <h3 className="text-lg font-semibold text-gray-900 mb-4">Bus Details</h3>
              
              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm text-gray-600">Bus Number</p>
                    <p className="text-xl font-bold text-gray-900">Bus {bus.busNumber}</p>
                  </div>
                  <div className="text-right">
                    <p className="text-sm text-gray-600">Capacity</p>
                    <p className="text-xl font-bold text-gray-900">{bus.capacity || 40} seats</p>
                  </div>
                </div>
                
                <div>
                  <p className="text-sm text-gray-600 mb-2">Route</p>
                  <p className="font-medium text-gray-900">{bus.routeName || 'Main Campus Route'}</p>
                </div>
                
                <div>
                  <p className="text-sm text-gray-600 mb-2">Driver</p>
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-full bg-blue-100 flex items-center justify-center text-blue-600">
                      <i className="fas fa-user"></i>
                    </div>
                    <div>
                      <p className="font-medium text-gray-900">{bus.driverName || 'Not Assigned'}</p>
                      {bus.driverId?.phone && (
                        <p className="text-sm text-gray-600">{bus.driverId.phone}</p>
                      )}
                    </div>
                  </div>
                </div>
                
                <div className="pt-4 border-t border-gray-100">
                  <p className="text-sm text-gray-600 mb-2">Vehicle ID</p>
                  <p className="font-mono font-medium text-gray-900">{bus.busId || 'N/A'}</p>
                </div>
              </div>
            </div>
          </div>

          {/* Map Section */}
          <div className="lg:col-span-2">
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
              <div className="p-4 border-b border-gray-200 flex items-center justify-between">
                <h3 className="text-lg font-semibold text-gray-900">Live Tracking Map</h3>
                <div className="flex items-center gap-2">
                  <button
                    onClick={() => setShowRoute(!showRoute)}
                    className={`px-3 py-1.5 rounded-lg text-sm font-medium ${
                      showRoute 
                        ? 'bg-blue-500 text-white' 
                        : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
                    }`}
                  >
                    <i className="fas fa-route mr-2"></i>
                    {showRoute ? 'Hide Route' : 'Show Route'}
                  </button>
                  <button
                    onClick={() => bus?.latitude && window.open(`https://www.google.com/maps?q=${bus.latitude},${bus.longitude}`, '_blank')}
                    disabled={!bus?.latitude}
                    className="px-3 py-1.5 bg-green-100 text-green-700 rounded-lg text-sm font-medium hover:bg-green-200 disabled:opacity-50"
                  >
                    <i className="fas fa-external-link-alt mr-2"></i>
                    Open Maps
                  </button>
                </div>
              </div>
              
              <div className="h-[400px]">
                <MapComponent
                  center={mapCenter}
                  zoom={13}
                  markers={mapMarkers}
                  routes={mapRoutes}
                  interactive={true}
                />
              </div>
            </div>

            {/* Quick Actions */}
            <div className="mt-6 grid grid-cols-1 md:grid-cols-3 gap-4">
              <button
                onClick={() => bus?.driverId?.phone && window.open(`tel:${bus.driverId.phone}`)}
                disabled={!bus?.driverId?.phone}
                className="p-4 bg-white border border-gray-200 rounded-xl hover:border-blue-300 hover:bg-blue-50 transition-all disabled:opacity-50"
              >
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-lg bg-blue-100 flex items-center justify-center text-blue-600">
                    <i className="fas fa-phone"></i>
                  </div>
                  <div className="text-left">
                    <p className="font-medium text-gray-900">Call Driver</p>
                    <p className="text-sm text-gray-600">Direct contact</p>
                  </div>
                </div>
              </button>
              
              <button
                onClick={() => navigator.clipboard.writeText(`Bus ${bus?.busNumber} - ${bus?.routeName}`)}
                className="p-4 bg-white border border-gray-200 rounded-xl hover:border-green-300 hover:bg-green-50 transition-all"
              >
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-lg bg-green-100 flex items-center justify-center text-green-600">
                    <i className="fas fa-copy"></i>
                  </div>
                  <div className="text-left">
                    <p className="font-medium text-gray-900">Copy Bus Info</p>
                    <p className="text-sm text-gray-600">Share details</p>
                  </div>
                </div>
              </button>
              
              <button
                onClick={() => alert('Emergency alert sent to administration')}
                className="p-4 bg-white border border-red-200 rounded-xl hover:border-red-300 hover:bg-red-50 transition-all"
              >
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-lg bg-red-100 flex items-center justify-center text-red-600">
                    <i className="fas fa-exclamation-triangle"></i>
                  </div>
                  <div className="text-left">
                    <p className="font-medium text-gray-900">Emergency</p>
                    <p className="text-sm text-gray-600">Report issue</p>
                  </div>
                </div>
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default StudentDashboard;