// client/src/pages/AdminPages.jsx
import React, { useState } from 'react';
import { Routes, Route, Navigate, Link } from 'react-router-dom';
import Dashboard from '../components/Admin/Dashboard';
import UserManagement from '../components/Admin/UserManagement';
import BusManagement from '../components/Admin/BusManagement';
import LiveMonitor from '../components/Admin/LiveMonitor';
import Navbar from '../components/Layout/Navbar';
import '../styles/admin.css';

function AdminPages() {
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const toggleSidebar = () => {
    setSidebarOpen(!sidebarOpen);
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <Navbar />
      
      {/* Main Layout with Sidebar */}
      <div className="flex">
        {/* Sidebar */}
        <div className={`${sidebarOpen ? 'w-64' : 'w-0'} bg-white border-r border-gray-200 h-[calc(100vh-4rem)] transition-all duration-300 overflow-hidden fixed md:relative z-20`}>
          {sidebarOpen && (
            <div className="p-6">
              {/* Sidebar Header */}
              <div className="mb-8">
                <h2 className="text-lg font-bold text-gray-900">Admin Panel</h2>
                <p className="text-sm text-gray-600">Management Dashboard</p>
              </div>

              {/* Navigation Menu */}
              <nav className="space-y-2">
                <Link
                  to="/admin/dashboard"
                  className="flex items-center gap-3 px-4 py-3 text-gray-700 rounded-lg hover:bg-blue-50 hover:text-blue-600 transition-colors group"
                >
                  <i className="fas fa-chart-bar text-gray-400 group-hover:text-blue-600"></i>
                  <span className="font-medium">Dashboard</span>
                </Link>

                <Link
                  to="/admin/users"
                  className="flex items-center gap-3 px-4 py-3 text-gray-700 rounded-lg hover:bg-blue-50 hover:text-blue-600 transition-colors group"
                >
                  <i className="fas fa-users text-gray-400 group-hover:text-blue-600"></i>
                  <span className="font-medium">User Management</span>
                </Link>

                <Link
                  to="/admin/buses"
                  className="flex items-center gap-3 px-4 py-3 text-gray-700 rounded-lg hover:bg-blue-50 hover:text-blue-600 transition-colors group"
                >
                  <i className="fas fa-bus text-gray-400 group-hover:text-blue-600"></i>
                  <span className="font-medium">Bus Management</span>
                </Link>

                <Link
                  to="/admin/monitor"
                  className="flex items-center gap-3 px-4 py-3 text-gray-700 rounded-lg hover:bg-blue-50 hover:text-blue-600 transition-colors group"
                >
                  <i className="fas fa-map-marker-alt text-gray-400 group-hover:text-blue-600"></i>
                  <span className="font-medium">Live Monitor</span>
                </Link>

                <div className="pt-4 mt-4 border-t border-gray-200">
                  <Link
                    to="/"
                    className="flex items-center gap-3 px-4 py-3 text-gray-700 rounded-lg hover:bg-gray-100 transition-colors"
                  >
                    <i className="fas fa-arrow-left text-gray-400"></i>
                    <span className="font-medium">Back to Home</span>
                  </Link>
                </div>
              </nav>
            </div>
          )}
        </div>

        {/* Main Content */}
        <div className={`flex-1 transition-all duration-300 ${sidebarOpen ? 'md:ml-64' : ''}`}>
          {/* Burger Menu Button for Mobile */}
          <div className="md:hidden bg-white border-b border-gray-200 p-4">
            <button
              onClick={toggleSidebar}
              className="p-2 rounded-lg bg-gray-100 hover:bg-gray-200 transition-colors"
            >
              <i className={`fas ${sidebarOpen ? 'fa-times' : 'fa-bars'} text-gray-700`}></i>
            </button>
          </div>

          {/* Content Area */}
          <div className="p-4 md:p-6">
            <Routes>
              <Route path="dashboard" element={<Dashboard />} />
              <Route path="users" element={<UserManagement />} />
              <Route path="buses" element={<BusManagement />} />
              <Route path="monitor" element={<LiveMonitor />} />
              <Route path="*" element={<Navigate to="/admin/dashboard" />} />
            </Routes>
          </div>
        </div>

        {/* Overlay for mobile */}
        {sidebarOpen && (
          <div
            className="fixed inset-0 bg-black bg-opacity-50 z-10 md:hidden"
            onClick={toggleSidebar}
          ></div>
        )}
      </div>
    </div>
  );
}

export default AdminPages;