// client/src/components/Admin/BusForm.jsx
import React, { useState, useEffect } from 'react';
import { busService } from '../../services/busService';
import { userService } from '../../services/userService';
import useGeolocation from '../../hooks/useGeolocation';

const BusForm = ({ bus, onSuccess, onCancel }) => {
  const [loading, setLoading] = useState(false);
  const [drivers, setDrivers] = useState([]);
  const [routes, setRoutes] = useState([]);
  const [showCreateRoute, setShowCreateRoute] = useState(false);
  const [formData, setFormData] = useState({
    busNumber: '',
    routeName: '',
    routeDescription: '',
    routeStops: [],
    capacity: 40,
    status: 'active',
    driverId: '',
    latitude: 20.5937,
    longitude: 78.9629
  });
  const [newStop, setNewStop] = useState('');
  const [errors, setErrors] = useState({});
  const { location, error: locationError, getCurrentPosition, isSupported } = useGeolocation();

  useEffect(() => {
    if (bus) {
      setFormData({
        busNumber: bus.busNumber || '',
        routeName: bus.routeName || '',
        routeDescription: bus.routeDescription || '',
        routeStops: bus.routeStops || [],
        capacity: bus.capacity || 40,
        status: bus.status || 'active',
        driverId: bus.driverId?._id || bus.driverId || '',
        latitude: bus.latitude || 20.5937,
        longitude: bus.longitude || 78.9629
      });
    }
    fetchAvailableDrivers();
    fetchRoutes();
  }, [bus]);

  const fetchAvailableDrivers = async () => {
    try {
      const response = await userService.getAllUsers();
      if (response.users) {
        const driversList = response.users.filter(u => u.role === 'driver');
        setDrivers(driversList);
      }
    } catch (error) {
      console.error('Error fetching drivers:', error);
    }
  };

  const fetchRoutes = async () => {
    try {
      const response = await busService.getRoutes();
      if (response.routes) {
        setRoutes(response.routes);
      }
    } catch (error) {
      console.error('Error fetching routes:', error);
    }
  };

  const validateForm = () => {
    const newErrors = {};
    
    if (!formData.busNumber.trim()) newErrors.busNumber = 'Bus number is required';
    if (!formData.routeName.trim()) newErrors.routeName = 'Route name is required';
    if (formData.capacity && (formData.capacity < 1 || formData.capacity > 100)) {
      newErrors.capacity = 'Capacity must be between 1 and 100';
    }
    if (!formData.latitude || !formData.longitude) {
      newErrors.location = 'Initial location is required';
    }
    
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const addRouteStop = () => {
    if (newStop.trim()) {
      setFormData(prev => ({
        ...prev,
        routeStops: [...prev.routeStops, newStop.trim()]
      }));
      setNewStop('');
    }
  };

  const removeRouteStop = (index) => {
    setFormData(prev => ({
      ...prev,
      routeStops: prev.routeStops.filter((_, i) => i !== index)
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!validateForm()) {
      return;
    }

    setLoading(true);
    try {
      const busData = {
        busNumber: formData.busNumber,
        routeName: formData.routeName,
        routeDescription: formData.routeDescription,
        routeStops: formData.routeStops,
        capacity: parseInt(formData.capacity),
        status: formData.status,
        driverId: formData.driverId || null,
        latitude: formData.latitude,
        longitude: formData.longitude
      };

      let response;
      if (bus) {
        response = await busService.updateBus(bus.id || bus._id, busData);
      } else {
        response = await busService.createBus(busData);
      }

      if (response.success) {
        onSuccess();
      } else {
        setErrors({ submit: response.message || 'Failed to save bus' });
      }

    } catch (error) {
      console.error('Error saving bus:', error);
      setErrors({ submit: error.message || 'Failed to save bus' });
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: name === 'capacity' ? parseInt(value) : value
    }));
    
    // Clear error for this field
    if (errors[name]) {
      setErrors(prev => ({
        ...prev,
        [name]: ''
      }));
    }
  };

  // Update location when geolocation is fetched
  useEffect(() => {
    if (location) {
      setFormData(prev => ({
        ...prev,
        latitude: location.latitude,
        longitude: location.longitude
      }));
    }
  }, [location]);

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      {errors.submit && (
        <div className="p-4 bg-red-50 border border-red-200 rounded-lg">
          <div className="flex items-center gap-2 text-red-700">
            <i className="fas fa-exclamation-circle"></i>
            <span>{errors.submit}</span>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            Bus Number *
          </label>
          <input
            type="text"
            name="busNumber"
            value={formData.busNumber}
            onChange={handleChange}
            className={`block w-full px-4 py-3 border ${
              errors.busNumber ? 'border-red-300' : 'border-gray-300'
            } rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500`}
            placeholder="MH-01-AB-1234"
          />
          {errors.busNumber && (
            <p className="mt-1 text-sm text-red-600">{errors.busNumber}</p>
          )}
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            Capacity *
          </label>
          <input
            type="number"
            name="capacity"
            value={formData.capacity}
            onChange={handleChange}
            min="1"
            max="100"
            className={`block w-full px-4 py-3 border ${
              errors.capacity ? 'border-red-300' : 'border-gray-300'
            } rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500`}
          />
          {errors.capacity && (
            <p className="mt-1 text-sm text-red-600">{errors.capacity}</p>
          )}
        </div>
      </div>

      {/* Route Selection */}
      <div>
        <label className="block text-sm font-medium text-gray-700 mb-2">
          Route *
        </label>
        <div className="flex gap-2">
          <select
            name="routeName"
            value={formData.routeName}
            onChange={(e) => {
              if (e.target.value === 'create-new') {
                setShowCreateRoute(true);
                setFormData(prev => ({ ...prev, routeName: '' }));
              } else {
                setFormData(prev => ({ ...prev, routeName: e.target.value }));
                setShowCreateRoute(false);
              }
            }}
            className={`flex-1 px-4 py-3 border ${
              errors.routeName ? 'border-red-300' : 'border-gray-300'
            } rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500`}
          >
            <option value="">Select existing route</option>
            {routes.map(route => (
              <option key={route.id} value={route.name}>
                {route.name} - {route.description}
              </option>
            ))}
            <option value="create-new">+ Create New Route</option>
          </select>
        </div>
        {errors.routeName && (
          <p className="mt-1 text-sm text-red-600">{errors.routeName}</p>
        )}
      </div>

      {/* Create New Route Form */}
      {showCreateRoute && (
        <div className="bg-blue-50 border border-blue-200 rounded-lg p-4 space-y-4">
          <h3 className="font-semibold text-gray-900">Create New Route</h3>
          
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Route Name *
            </label>
            <input
              type="text"
              name="routeName"
              value={formData.routeName}
              onChange={handleChange}
              placeholder="e.g., North Campus Route"
              className="block w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Route Description
            </label>
            <textarea
              name="routeDescription"
              value={formData.routeDescription}
              onChange={handleChange}
              placeholder="Route details and stops"
              rows="3"
              className="block w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Route Stops
            </label>
            <div className="flex gap-2 mb-2">
              <input
                type="text"
                value={newStop}
                onChange={(e) => setNewStop(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && (e.preventDefault(), addRouteStop())}
                placeholder="Enter stop name and press Enter"
                className="flex-1 px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
              />
              <button
                type="button"
                onClick={addRouteStop}
                className="px-4 py-3 bg-blue-500 text-white rounded-lg hover:bg-blue-600"
              >
                <i className="fas fa-plus"></i>
              </button>
            </div>
            
            <div className="space-y-2">
              {formData.routeStops.map((stop, index) => (
                <div key={index} className="flex items-center justify-between bg-white p-3 rounded border border-gray-200">
                  <span className="text-gray-900">{index + 1}. {stop}</span>
                  <button
                    type="button"
                    onClick={() => removeRouteStop(index)}
                    className="text-red-500 hover:text-red-700"
                  >
                    <i className="fas fa-times"></i>
                  </button>
                </div>
              ))}
            </div>
          </div>

          <button
            type="button"
            onClick={() => setShowCreateRoute(false)}
            className="text-sm text-blue-600 hover:text-blue-700 font-medium"
          >
            ← Back to Route Selection
          </button>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            Status
          </label>
          <select
            name="status"
            value={formData.status}
            onChange={handleChange}
            className="block w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
          >
            <option value="active">Active</option>
            <option value="inactive">Inactive</option>
            <option value="maintenance">Maintenance</option>
          </select>
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            Assign Driver (Optional)
          </label>
          <select
            name="driverId"
            value={formData.driverId}
            onChange={handleChange}
            className="block w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
          >
            <option value="">Unassigned</option>
            {drivers.map(driver => (
              <option key={driver.id} value={driver.id}>
                {driver.name} ({driver.email})
              </option>
            ))}
          </select>
        </div>
      </div>

      {/* Location Management */}
      <div className="bg-gray-50 rounded-lg p-4 border border-gray-200 space-y-4">
        <div className="flex items-center justify-between">
          <h3 className="text-sm font-semibold text-gray-700">Initial Location</h3>
          <button
            type="button"
            onClick={getCurrentPosition}
            disabled={!isSupported}
            className="px-3 py-1 text-xs bg-blue-500 text-white rounded hover:bg-blue-600 disabled:bg-gray-300 disabled:cursor-not-allowed flex items-center gap-1"
          >
            <i className="fas fa-location-crosshairs"></i>
            Use Current Location
          </button>
        </div>

        {!isSupported && (
          <p className="text-sm text-amber-600">
            <i className="fas fa-exclamation-triangle mr-1"></i>
            Geolocation is not supported by your browser
          </p>
        )}

        {locationError && (
          <p className="text-sm text-red-600">
            <i className="fas fa-exclamation-circle mr-1"></i>
            {locationError}
          </p>
        )}

        {location && (
          <div className="bg-green-50 p-3 rounded border border-green-200 text-sm text-green-700">
            <i className="fas fa-check-circle mr-2"></i>
            Location detected and updated
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
            <label className="block text-xs font-medium text-gray-600 mb-1">
              Latitude *
            </label>
            <input
              type="number"
              name="latitude"
              value={formData.latitude}
              onChange={handleChange}
              step="0.000001"
              className={`block w-full px-4 py-3 border ${
                errors.location ? 'border-red-300' : 'border-gray-300'
              } rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 text-sm`}
            />
          </div>
          <div>
            <label className="block text-xs font-medium text-gray-600 mb-1">
              Longitude *
            </label>
            <input
              type="number"
              name="longitude"
              value={formData.longitude}
              onChange={handleChange}
              step="0.000001"
              className={`block w-full px-4 py-3 border ${
                errors.location ? 'border-red-300' : 'border-gray-300'
              } rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 text-sm`}
            />
          </div>
        </div>
        {errors.location && (
          <p className="text-sm text-red-600">{errors.location}</p>
        )}
        <p className="text-xs text-gray-500">
          Default: India center (20.5937°N, 78.9629°E). Update manually or use "Get Current Location" button.
        </p>
      </div>

      <div className="flex items-center justify-end gap-4 pt-6 border-t border-gray-200">
        <button
          type="button"
          onClick={onCancel}
          className="px-6 py-3 border border-gray-300 rounded-lg font-semibold text-gray-700 hover:bg-gray-50 transition-colors"
        >
          Cancel
        </button>
        <button
          type="submit"
          disabled={loading}
          className="px-6 py-3 bg-gradient-to-r from-blue-500 to-blue-600 text-white rounded-lg font-semibold hover:from-blue-600 hover:to-blue-700 transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
        >
          {loading ? (
            <>
              <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-white"></div>
              Saving...
            </>
          ) : (
            <>
              <i className="fas fa-save"></i>
              {bus ? 'Update Bus' : 'Create Bus'}
            </>
          )}
        </button>
      </div>
    </form>
  );
};

export default BusForm;